//! Motion deblur via Richardson–Lucy deconvolution against a directional
//! line point-spread function (PSF).
//!
//! Unlike [`crate::mesh_residual_deblur`] — a topology-gated residual sharpener
//! that has no notion of a blur kernel — this models the actual physics of
//! camera/subject motion: a pixel is smeared along a straight line of a given
//! angle and length. We build that line PSF and run iterative Richardson–Lucy
//! (RL) deconvolution to invert it.
//!
//! Two entry points support the "assisted default + auto guess" UX:
//!   - [`motion_deblur_rgb_f32`] — deconvolve with a caller-supplied
//!     (angle, length): the reliable, user-driven path.
//!   - [`estimate_motion_psf`] — blindly estimate (angle, length) from the image
//!     so the UI can prefill the controls ("guess" button). v1 heuristic:
//!     angle = direction of least directional-gradient energy; length = first
//!     autocorrelation notch of the directional derivative along that axis.
//!
//! Spatial-domain on purpose: the line PSF is sparse (~`length` taps), so an
//! RL iteration is O(W·H·length), not O(W·H·kernel²), and we avoid pulling an
//! FFT dependency into the WASM build. Per-channel on linear RGB `[0,1]`,
//! row-major, reflect-padded borders.

use serde::Serialize;
use std::collections::BTreeMap;

/// Caller-supplied motion PSF + deconvolution controls.
#[derive(Clone, Debug)]
pub struct MotionDeblurConfig {
    /// Blur direction in degrees (0 = +x / horizontal, measured CCW). The PSF is
    /// symmetric, so `angle` and `angle + 180` are equivalent.
    pub angle_deg: f32,
    /// Blur extent in pixels — the length of the motion streak. `<= 1` is a
    /// no-op (nothing to invert).
    pub length_px: f32,
    /// Richardson–Lucy iterations. More = sharper but amplifies noise/ringing.
    /// Clamped to `[0, 200]`.
    pub iterations: u32,
    /// Per-iteration step damping in `[0, 1]`. `1.0` = standard RL; lower values
    /// soften each multiplicative update to suppress ringing on noisy input.
    pub damping: f32,
    /// Emit the diagnostic layer set ([`MotionDeblurResult::layers`]) for the UX
    /// to view + download (PSF, residual/error map, detail-gain map). Off keeps
    /// the result lean for batch use.
    pub emit_layers: bool,
}

/// A named single-channel `[0,1]` layer surfaced to the deblur UX (view +
/// download). Each carries its own dimensions (the PSF layer is small) and a
/// render hint so the UI can colourize masks vs heatmaps consistently.
#[derive(Clone, Debug)]
pub struct DeblurLayer {
    /// Stable id, e.g. `"psf"`, `"residual"`, `"detail_gain"`.
    pub name: String,
    /// Human label for the UI, e.g. `"Motion PSF"`.
    pub label: String,
    pub width: u32,
    pub height: u32,
    /// Row-major single channel, normalized to `[0,1]`.
    pub data: Vec<f32>,
    /// UI render hint: `"gray"` | `"heat"` | `"mask"`.
    pub colormap: &'static str,
}

impl Default for MotionDeblurConfig {
    fn default() -> Self {
        Self {
            angle_deg: 0.0,
            length_px: 9.0,
            iterations: 24,
            damping: 1.0,
            emit_layers: false,
        }
    }
}

/// Self-describing record of what the deconvolution did (mirrors the
/// certificate convention of [`crate::mesh_residual_deblur`]).
#[derive(Serialize, Clone, Debug)]
pub struct MotionDeblurCertificate {
    pub schema_version: &'static str,
    pub width: u32,
    pub height: u32,
    pub angle_deg: f32,
    pub length_px: f32,
    pub iterations: u32,
    pub psf_taps: usize,
    pub mean_abs_delta: f32,
    pub max_channel_delta: f32,
}

pub struct MotionDeblurResult {
    /// Deconvolved linear RGB `[0,1]`, row-major, same layout as the input.
    pub rgb: Vec<f32>,
    pub certificate: MotionDeblurCertificate,
    /// Diagnostic layers for the UX (empty unless `cfg.emit_layers`).
    pub layers: Vec<DeblurLayer>,
}

const SCHEMA_VERSION: &str = "motion_deblur/v1_richardson_lucy_line_psf";

/// Reflect an index into `[0, n)` (mirror padding without edge repetition).
#[inline]
fn reflect(i: i32, n: i32) -> usize {
    if n <= 1 {
        return 0;
    }
    let period = 2 * (n - 1);
    let mut m = i.rem_euclid(period);
    if m >= n {
        m = period - m;
    }
    m as usize
}

#[inline]
fn sample_bilinear(buf: &[f32], w: usize, h: usize, x: f32, y: f32) -> f32 {
    let x0 = x.floor();
    let y0 = y.floor();
    let fx = x - x0;
    let fy = y - y0;
    let (wi, hi) = (w as i32, h as i32);
    let x0i = x0 as i32;
    let y0i = y0 as i32;
    let p = |xx: i32, yy: i32| -> f32 { buf[reflect(yy, hi) * w + reflect(xx, wi)] };
    let top = p(x0i, y0i) * (1.0 - fx) + p(x0i + 1, y0i) * fx;
    let bot = p(x0i, y0i + 1) * (1.0 - fx) + p(x0i + 1, y0i + 1) * fx;
    top * (1.0 - fy) + bot * fy
}

/// Build the line-PSF as sparse integer taps `(dx, dy, weight)`, bilinearly
/// splatting the continuous line samples onto the integer grid and normalizing
/// to sum 1. A `BTreeMap` keeps it deterministic (no `HashMap` RandomState in
/// the wasm build).
fn build_line_psf(angle_deg: f32, length_px: f32) -> Vec<(i32, i32, f32)> {
    let length = length_px.max(1.0);
    let (s, c) = angle_deg.to_radians().sin_cos();
    let samples = (length.ceil() as i32).max(1);
    let half = (length - 1.0) / 2.0;
    let mut acc: BTreeMap<(i32, i32), f32> = BTreeMap::new();
    for i in 0..samples {
        let t = if samples == 1 {
            0.0
        } else {
            (i as f32) / (samples as f32 - 1.0) * (length - 1.0) - half
        };
        let x = c * t;
        let y = s * t;
        let x0 = x.floor();
        let y0 = y.floor();
        let fx = x - x0;
        let fy = y - y0;
        let (x0i, y0i) = (x0 as i32, y0 as i32);
        for (ox, oy, wt) in [
            (0, 0, (1.0 - fx) * (1.0 - fy)),
            (1, 0, fx * (1.0 - fy)),
            (0, 1, (1.0 - fx) * fy),
            (1, 1, fx * fy),
        ] {
            if wt > 0.0 {
                *acc.entry((x0i + ox, y0i + oy)).or_insert(0.0) += wt;
            }
        }
    }
    let sum: f32 = acc.values().sum();
    let inv = if sum > 0.0 { 1.0 / sum } else { 1.0 };
    acc.into_iter()
        .map(|((dx, dy), w)| (dx, dy, w * inv))
        .collect()
}

/// Convolve a single channel with the sparse PSF taps. `mirror=false` applies
/// the PSF (`out[p] = Σ src[p-tap]·w`); `mirror=true` applies the 180°-flipped
/// PSF (`out[p] = Σ src[p+tap]·w`), as RL's correction step requires.
fn convolve_taps(
    src: &[f32],
    w: usize,
    h: usize,
    taps: &[(i32, i32, f32)],
    mirror: bool,
) -> Vec<f32> {
    let mut out = vec![0.0f32; w * h];
    let (wi, hi) = (w as i32, h as i32);
    for y in 0..h {
        for x in 0..w {
            let mut acc = 0.0f32;
            for &(dx, dy, wt) in taps {
                let (sx, sy) = if mirror {
                    (x as i32 + dx, y as i32 + dy)
                } else {
                    (x as i32 - dx, y as i32 - dy)
                };
                acc += src[reflect(sy, hi) * w + reflect(sx, wi)] * wt;
            }
            out[y * w + x] = acc;
        }
    }
    out
}

/// Standard (damped) Richardson–Lucy deconvolution of one channel.
fn richardson_lucy(
    blurred: &[f32],
    w: usize,
    h: usize,
    taps: &[(i32, i32, f32)],
    iters: u32,
    damping: f32,
) -> Vec<f32> {
    let eps = 1e-6f32;
    let mut est = blurred.to_vec();
    for _ in 0..iters {
        let conv = convolve_taps(&est, w, h, taps, false);
        let mut ratio = vec![0.0f32; w * h];
        for i in 0..ratio.len() {
            ratio[i] = blurred[i] / (conv[i] + eps);
        }
        let corr = convolve_taps(&ratio, w, h, taps, true);
        for i in 0..est.len() {
            // damping: blend the multiplicative factor toward 1 (no update).
            let factor = 1.0 + damping * (corr[i] - 1.0);
            est[i] = (est[i] * factor).max(0.0);
        }
    }
    est
}

/// Deconvolve interleaved linear RGB `[0,1]` against the configured motion PSF.
pub fn motion_deblur_rgb_f32(
    rgb: &[f32],
    width: u32,
    height: u32,
    cfg: &MotionDeblurConfig,
) -> Result<MotionDeblurResult, String> {
    let (w, h) = (width as usize, height as usize);
    if w == 0 || h == 0 {
        return Err("zero-sized image".to_string());
    }
    if rgb.len() != w * h * 3 {
        return Err(format!(
            "rgb len {} != width*height*3 ({})",
            rgb.len(),
            w * h * 3
        ));
    }

    let iters = cfg.iterations.min(200);
    let damping = cfg.damping.clamp(0.0, 1.0);
    let taps = build_line_psf(cfg.angle_deg, cfg.length_px);
    let identity = cfg.length_px <= 1.0 || taps.len() <= 1 || iters == 0;

    let mut out = vec![0.0f32; rgb.len()];
    let mut max_channel_delta = 0.0f32;
    let mut sum_delta = 0.0f64;

    for c in 0..3usize {
        let mut plane = vec![0.0f32; w * h];
        for i in 0..w * h {
            plane[i] = rgb[i * 3 + c].clamp(0.0, 1.0);
        }
        let deconv = if identity {
            plane.clone()
        } else {
            richardson_lucy(&plane, w, h, &taps, iters, damping)
        };
        for i in 0..w * h {
            let v = deconv[i].clamp(0.0, 1.0);
            out[i * 3 + c] = v;
            let d = (v - plane[i]).abs();
            if d > max_channel_delta {
                max_channel_delta = d;
            }
            sum_delta += d as f64;
        }
    }

    let mean_abs_delta = (sum_delta / (w * h * 3) as f64) as f32;
    let layers = if cfg.emit_layers {
        build_layers(rgb, &out, w, h, &taps, identity)
    } else {
        Vec::new()
    };
    Ok(MotionDeblurResult {
        rgb: out,
        certificate: MotionDeblurCertificate {
            schema_version: SCHEMA_VERSION,
            width,
            height,
            angle_deg: cfg.angle_deg,
            length_px: cfg.length_px,
            iterations: iters,
            psf_taps: taps.len(),
            mean_abs_delta,
            max_channel_delta,
        },
        layers,
    })
}

/// Normalize a buffer to `[0,1]` by its own max (robust to all-zero).
fn normalize01(mut v: Vec<f32>) -> Vec<f32> {
    let max = v.iter().cloned().fold(0.0f32, f32::max);
    if max > 1e-8 {
        let inv = 1.0 / max;
        for x in v.iter_mut() {
            *x *= inv;
        }
    }
    v
}

/// Build the diagnostic layer set: the PSF image, the residual/error map
/// (`|input − reconvolve(output)|` — where the deconvolution couldn't explain
/// the input: motion mismatch, occlusion, moving objects), the inverse
/// confidence/support map (`1 - residual_norm` so bright = well-supported
/// structure), and the detail-gain map (`|output − input|` — where sharpening
/// landed). Both image-sized maps are per-pixel means over channels,
/// normalized for display.
fn build_layers(
    input: &[f32],
    output: &[f32],
    w: usize,
    h: usize,
    taps: &[(i32, i32, f32)],
    identity: bool,
) -> Vec<DeblurLayer> {
    let n = w * h;
    let mut residual = vec![0.0f32; n];
    let mut confidence = vec![1.0f32; n];
    let mut detail = vec![0.0f32; n];

    // reconvolve each output channel with the forward PSF to get the model of
    // the input, then accumulate per-pixel error and gain.
    for c in 0..3usize {
        let mut out_plane = vec![0.0f32; n];
        for i in 0..n {
            out_plane[i] = output[i * 3 + c];
        }
        let recon = if identity {
            out_plane.clone()
        } else {
            convolve_taps(&out_plane, w, h, taps, false)
        };
        for i in 0..n {
            let inp = input[i * 3 + c].clamp(0.0, 1.0);
            residual[i] += (inp - recon[i]).abs() / 3.0;
            detail[i] += (output[i * 3 + c] - inp).abs() / 3.0;
        }
    }

    let residual_norm = normalize01(residual);
    for i in 0..n {
        confidence[i] = 1.0 - residual_norm[i];
    }

    // PSF image: rasterize taps into their bounding box for a visual confirm.
    let (psf_w, psf_h, psf_data) = render_psf_image(taps);

    vec![
        DeblurLayer {
            name: "psf".to_string(),
            label: "Motion PSF".to_string(),
            width: psf_w,
            height: psf_h,
            data: psf_data,
            colormap: "gray",
        },
        DeblurLayer {
            name: "residual".to_string(),
            label: "Residual / error".to_string(),
            width: w as u32,
            height: h as u32,
            data: residual_norm,
            colormap: "heat",
        },
        DeblurLayer {
            name: "confidence".to_string(),
            label: "Reconstruction confidence".to_string(),
            width: w as u32,
            height: h as u32,
            data: confidence,
            colormap: "mask",
        },
        DeblurLayer {
            name: "detail_gain".to_string(),
            label: "Detail gain".to_string(),
            width: w as u32,
            height: h as u32,
            data: normalize01(detail),
            colormap: "mask",
        },
    ]
}

/// Rasterize the sparse PSF taps into a small dense `[0,1]` image (its own
/// bounding box, normalized by peak), for a visual confirm of angle/length.
fn render_psf_image(taps: &[(i32, i32, f32)]) -> (u32, u32, Vec<f32>) {
    if taps.is_empty() {
        return (1, 1, vec![0.0]);
    }
    let (mut min_x, mut max_x, mut min_y, mut max_y) = (i32::MAX, i32::MIN, i32::MAX, i32::MIN);
    for &(dx, dy, _) in taps {
        min_x = min_x.min(dx);
        max_x = max_x.max(dx);
        min_y = min_y.min(dy);
        max_y = max_y.max(dy);
    }
    // pad by 1px so the line isn't flush against the edge.
    let pw = (max_x - min_x + 3).max(1) as usize;
    let ph = (max_y - min_y + 3).max(1) as usize;
    let mut data = vec![0.0f32; pw * ph];
    let peak = taps.iter().map(|t| t.2).fold(0.0f32, f32::max).max(1e-8);
    for &(dx, dy, wt) in taps {
        let x = (dx - min_x + 1) as usize;
        let y = (dy - min_y + 1) as usize;
        data[y * pw + x] = (wt / peak).clamp(0.0, 1.0);
    }
    (pw as u32, ph as u32, data)
}

/// Blindly estimate `(angle_deg, length_px)` from the image so the UI can
/// prefill the motion controls. v1 heuristic — good enough to seed a
/// user-adjustable guess, not a precise PSF identifier:
///   - **Angle:** linear motion blur attenuates high-frequency content *along*
///     the motion direction, so the directional derivative has least energy
///     there. We sweep 0–180° and pick the minimum-energy direction.
///   - **Length:** along that axis the autocorrelation of the directional
///     derivative has its first notch near the blur length; we return the lag
///     of the first local minimum (bounded).
pub fn estimate_motion_psf(rgb: &[f32], width: u32, height: u32) -> (f32, f32) {
    let (w, h) = (width as usize, height as usize);
    if w < 8 || h < 8 || rgb.len() != w * h * 3 {
        return (0.0, 9.0);
    }
    let mut lum = vec![0.0f32; w * h];
    for i in 0..w * h {
        lum[i] = 0.299 * rgb[i * 3] + 0.587 * rgb[i * 3 + 1] + 0.114 * rgb[i * 3 + 2];
    }

    // --- angle: minimize directional-derivative energy --------------------
    let step = if w.max(h) > 512 { 3 } else { 2 };
    let mut best_angle = 0.0f32;
    let mut best_energy = f32::INFINITY;
    let mut a = 0.0f32;
    while a < 180.0 {
        let (s, c) = a.to_radians().sin_cos();
        let mut energy = 0.0f64;
        let mut count = 0u64;
        let mut y = 2;
        while y < h - 2 {
            let mut x = 2;
            while x < w - 2 {
                let fwd = sample_bilinear(&lum, w, h, x as f32 + c, y as f32 + s);
                let bwd = sample_bilinear(&lum, w, h, x as f32 - c, y as f32 - s);
                let d = fwd - bwd;
                energy += (d * d) as f64;
                count += 1;
                x += step;
            }
            y += step;
        }
        let e = (energy / count.max(1) as f64) as f32;
        if e < best_energy {
            best_energy = e;
            best_angle = a;
        }
        a += 2.0;
    }

    // --- length: first autocorrelation notch of the directional derivative
    // along the estimated motion axis ------------------------------------
    let (s, c) = best_angle.to_radians().sin_cos();
    let max_lag = (w.min(h) / 2).clamp(4, 64);
    // build the 1-D directional-derivative signal by walking a few scan lines
    // along the motion axis and concatenating; cheap proxy for the projection.
    let mut deriv: Vec<f32> = Vec::new();
    let mut yc = (h / 4) as f32;
    while yc < (3 * h / 4) as f32 {
        let mut t = 2.0f32;
        let mut xc = (w / 4) as f32;
        let mut ycur = yc;
        while t < (w.min(h)) as f32 / 2.0 && xc > 1.0 && xc < (w - 1) as f32 && ycur > 1.0
            && ycur < (h - 1) as f32
        {
            let fwd = sample_bilinear(&lum, w, h, xc + c, ycur + s);
            let bwd = sample_bilinear(&lum, w, h, xc - c, ycur - s);
            deriv.push(fwd - bwd);
            xc += c;
            ycur += s;
            t += 1.0;
        }
        yc += (h as f32 / 6.0).max(1.0);
    }
    if deriv.len() < max_lag + 4 {
        return (best_angle, 9.0);
    }
    let mean: f32 = deriv.iter().sum::<f32>() / deriv.len() as f32;
    let ac = |lag: usize| -> f32 {
        let mut num = 0.0f64;
        for i in 0..deriv.len() - lag {
            num += ((deriv[i] - mean) * (deriv[i + lag] - mean)) as f64;
        }
        num as f32
    };
    let zero = ac(0).max(1e-6);
    let mut best_len = 9.0f32;
    let mut prev = 1.0f32;
    for lag in 2..max_lag {
        let r = ac(lag) / zero;
        // first local minimum that dips below zero correlation ~ blur length
        if r < 0.0 && r > prev {
            best_len = lag as f32;
            break;
        }
        prev = r;
    }
    (best_angle, best_len.clamp(2.0, 64.0))
}

#[cfg(test)]
mod tests {
    use super::*;

    /// Convolve an image with a line PSF (forward blur) for test fixtures.
    fn blur(rgb: &[f32], w: usize, h: usize, angle: f32, length: f32) -> Vec<f32> {
        let taps = build_line_psf(angle, length);
        let mut out = vec![0.0f32; rgb.len()];
        for c in 0..3 {
            let mut plane = vec![0.0f32; w * h];
            for i in 0..w * h {
                plane[i] = rgb[i * 3 + c];
            }
            let b = convolve_taps(&plane, w, h, &taps, false);
            for i in 0..w * h {
                out[i * 3 + c] = b[i];
            }
        }
        out
    }

    #[test]
    fn line_psf_normalized_and_centered() {
        let taps = build_line_psf(0.0, 5.0);
        let sum: f32 = taps.iter().map(|t| t.2).sum();
        assert!((sum - 1.0).abs() < 1e-5, "psf must sum to 1, got {sum}");
        // horizontal PSF: all taps on row 0
        assert!(taps.iter().all(|t| t.1 == 0), "0deg psf should be a horizontal line");
    }

    #[test]
    fn identity_when_length_one() {
        let (w, h) = (16usize, 16usize);
        let mut rgb = vec![0.3f32; w * h * 3];
        rgb[8 * w * 3 + 8 * 3] = 0.9; // a bright spot
        let cfg = MotionDeblurConfig { length_px: 1.0, ..Default::default() };
        let out = motion_deblur_rgb_f32(&rgb, w as u32, h as u32, &cfg).unwrap();
        for (a, b) in rgb.iter().zip(out.rgb.iter()) {
            assert!((a - b).abs() < 1e-6, "length<=1 must be a no-op");
        }
    }

    #[test]
    fn recovers_a_horizontally_blurred_edge() {
        // sharp vertical edge -> horizontal motion blur -> RL should re-steepen it.
        let (w, h) = (48usize, 24usize);
        let mut sharp = vec![0.0f32; w * h * 3];
        for y in 0..h {
            for x in 0..w {
                let v = if x < w / 2 { 0.15 } else { 0.85 };
                for c in 0..3 {
                    sharp[(y * w + x) * 3 + c] = v;
                }
            }
        }
        let blurred = blur(&sharp, w, h, 0.0, 11.0);
        let cfg = MotionDeblurConfig {
            angle_deg: 0.0,
            length_px: 11.0,
            iterations: 30,
            damping: 1.0,
            emit_layers: false,
        };
        let out = motion_deblur_rgb_f32(&blurred, w as u32, h as u32, &cfg).unwrap();

        // edge sharpness = max horizontal gradient on the center row, channel 0.
        let grad = |img: &[f32]| -> f32 {
            let y = h / 2;
            let mut g = 0.0f32;
            for x in 1..w {
                let d = (img[(y * w + x) * 3] - img[(y * w + x - 1) * 3]).abs();
                if d > g {
                    g = d;
                }
            }
            g
        };
        let g_blur = grad(&blurred);
        let g_deconv = grad(&out.rgb);
        assert!(
            g_deconv > g_blur * 1.5,
            "RL should re-sharpen the blurred edge: blur grad {g_blur}, deconv grad {g_deconv}"
        );
    }

    #[test]
    fn emits_layer_set_when_requested() {
        let (w, h) = (24usize, 16usize);
        let rgb = vec![0.4f32; w * h * 3];
        let cfg = MotionDeblurConfig {
            angle_deg: 30.0,
            length_px: 9.0,
            iterations: 6,
            emit_layers: true,
            ..Default::default()
        };
        let out = motion_deblur_rgb_f32(&rgb, w as u32, h as u32, &cfg).unwrap();
        let names: Vec<&str> = out.layers.iter().map(|l| l.name.as_str()).collect();
        assert!(names.contains(&"psf"), "expected psf layer");
        assert!(names.contains(&"residual"), "expected residual layer");
        assert!(names.contains(&"confidence"), "expected confidence layer");
        assert!(names.contains(&"detail_gain"), "expected detail_gain layer");
        for l in &out.layers {
            assert_eq!(
                l.data.len(),
                (l.width * l.height) as usize,
                "layer {} data must match its dims",
                l.name
            );
            assert!(
                l.data.iter().all(|&v| (0.0..=1.0).contains(&v)),
                "layer {} must be normalized to [0,1]",
                l.name
            );
        }
    }

    #[test]
    fn blind_estimate_finds_horizontal_angle() {
        // ISOTROPIC pseudo-random noise (decorrelated x/y so the only directional
        // structure comes from the blur), horizontally blurred -> estimator ~0/180.
        let (w, h) = (64usize, 64usize);
        let mut img = vec![0.0f32; w * h * 3];
        for y in 0..h {
            for x in 0..w {
                let mut s = (x as u32)
                    .wrapping_mul(73856093)
                    ^ (y as u32).wrapping_mul(19349663);
                s = s.wrapping_mul(2654435761);
                let v = ((s >> 8) & 0xff) as f32 / 255.0;
                for c in 0..3 {
                    img[(y * w + x) * 3 + c] = v;
                }
            }
        }
        let blurred = blur(&img, w, h, 0.0, 13.0);
        let (angle, length) = estimate_motion_psf(&blurred, w as u32, h as u32);
        let horiz = angle < 15.0 || angle > 165.0;
        assert!(horiz, "estimated angle {angle} should be ~horizontal");
        assert!(length >= 2.0, "estimated length {length} should be positive");
    }
}
